    ---@type LxBehaviour
    self._behaviour = LxBehaviour:New()
end

function LDefenceWarBaseCtrl:Init()

end

function LDefenceWarBaseCtrl:Destroy()
    if self._behaviour then
        self._behaviour:Dispose()
    end
    self:OnDestroy()

    table.removeall(self)
