end

function LDefenceWarBaseCtrl:EventRemoveAll()
    local register = self._behaviour
    if (register) then
        register:RemoveEventHandlerList()
    end
end

function LDefenceWarBaseCtrl:EventRecv(event,  func, target)
    local register = self._behaviour
    if register then
        register:AddEventHandler(event, func, target)
    end
end

function LDefenceWarBaseCtrl:EventRemove(event)
    local register = self._behaviour
    if register then
        register:RemoveEventHandler(event)
